    44→function fmtPdfDate(raw: any): string {
    45→  if (!raw) return '-';
    46→  const d = parseDateSafe(raw);
    47→  if (isNaN(d.getTime())) return '-';
    48→  return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
    49→}
    50→
    51→function fmtRsPdf(n: any): string {
    52→  const num = Math.abs(Number(n || 0));
    53→  const [intPart, decPart] = num.toFixed(2).split('.');
    54→  let formatted = '';
    55→  if (intPart.length <= 3) {
    56→    formatted = intPart;
    57→  } else {
    58→    formatted = intPart.slice(-3);
    59→    let rest = intPart.slice(0, -3);
    60→    while (rest.length > 2) { formatted = rest.slice(-2) + ',' + formatted; rest = rest.slice(0, -2); }
    61→    if (rest.length > 0) formatted = rest + ',' + formatted;
    62→  }
    63→  return `Rs.${formatted}.${decPart}`;
    64→}
