    19→  /**
    20→   * Exports all user collections to a JSON object.
    21→   * Returns a structured object that can be passed back to restoreBackup.
    22→   */
    23→  createBackup: async (userId: string) => {
    24→    const backupData: any = {
    25→      version: '1.0',
    26→      timestamp: new Date().toISOString(),
    27→      data: {},
    28→    };
    29→
    30→    for (const colName of BACKUP_COLLECTIONS) {
