    32→      const snap = await getDocs(colRef);
    33→      backupData.data[colName] = snap.docs.map(d => ({ id: d.id, ...d.data() }));
    34→    }
    35→
    36→    return backupData;
    37→  },
    38→
    39→  /**
    40→   * Restores data from a JSON object into Firestore.
    41→   *
    42→   * FIX: The previous implementation reused a single writeBatch object after calling
    43→   * .commit() on it.  Calling .set() on an already-committed batch throws
    44→   * "A write batch can no longer be used after commit() has been called."
    45→   * This crashed every restore that contained more than 450 records.
    46→   *
    47→   * Fix: create a fresh writeBatch after each commit().
    48→   */
    49→  restoreBackup: async (userId: string, backupData: any) => {
    50→    if (!backupData || !backupData.data) throw new Error('Invalid Backup File');
    51→
    52→    const MAX_BATCH_SIZE = 450; // Firestore hard limit is 500
    53→    let batch = writeBatch(db);   // ← new batch for each chunk
    54→    let opCount = 0;
    55→
    56→    const collections = Object.keys(backupData.data);
    57→
    58→    for (const colName of collections) {
    59→      const items = backupData.data[colName];
    60→      if (!Array.isArray(items)) continue;
    61→
    62→      for (const item of items) {
    63→        const { id, ...data } = item;
    64→        const docRef = id
    65→          ? doc(db, `users/${userId}/${colName}`, id)
    66→          : doc(collection(db, `users/${userId}/${colName}`));
    67→
    68→        batch.set(docRef, data, { merge: true });
    69→        opCount++;
    70→
    71→        if (opCount >= MAX_BATCH_SIZE) {
    72→          await batch.commit();
    73→          // FIX: Create a FRESH batch — never reuse after commit().
    74→          batch = writeBatch(db);
    75→          opCount = 0;
    76→        }
