   172→        for (let i = 0; i < byteChars.length; i++) {
   173→          byteNumbers[i] = byteChars.charCodeAt(i);
   174→        }
   175→        const blob = new Blob([new Uint8Array(byteNumbers)], { type: 'application/pdf' });
   176→        await webShare(blob, filename);
   177→      }
