    29→function fmtDate(d: any): string {
    30→  try {
    31→    let dt: Date;
    32→    if (d?.toDate) {
    33→      dt = d.toDate();
    34→    } else if (typeof d === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(d)) {
    35→      const [y, mo, day] = d.split('-').map(Number);
    36→      dt = new Date(y, mo - 1, day);
    37→    } else {
    38→      dt = new Date(d || 0);
    39→    }
    40→    return dt.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
    41→  } catch { return String(d || ''); }
    42→}
    43→
    44→function fmtRupee(n: any): string {
    45→  const num = Math.abs(Number(n || 0));
    46→  const [intPart, decPart] = num.toFixed(2).split('.');
    47→  let formatted = '';
    48→  if (intPart.length <= 3) {
    49→    formatted = intPart;
    50→  } else {
    51→    formatted = intPart.slice(-3);
    52→    let rest = intPart.slice(0, -3);
    53→    while (rest.length > 2) {
    54→      formatted = rest.slice(-2) + ',' + formatted;
    55→      rest = rest.slice(0, -2);
    56→    }
    57→    if (rest.length > 0) formatted = rest + ',' + formatted;
    58→  }
    59→  return `Rs.${formatted}.${decPart}`;
    60→}
