    10→async function getDriveAccessToken(): Promise<string> {
    11→  // 1. Reuse the token obtained at login (no popup needed)
    12→  const stored = GoogleTokenService.get();
    13→  if (stored && GoogleTokenService.hasScope(DRIVE_SCOPE)) return stored;
    14→
    15→  // 2. Token expired / not stored → re-auth with both scopes.
    16→  //    No 'consent' prompt: user already granted access at login.
    17→  const auth = getAuth();
    18→  const provider = new GoogleAuthProvider();
    19→  ALL_SCOPES.forEach(s => provider.addScope(s));
    20→  provider.setCustomParameters({ prompt: 'select_account' });
    21→
    22→  const result = await signInWithPopup(auth, provider);
    23→  const credential = GoogleAuthProvider.credentialFromResult(result);
    24→  if (!credential?.accessToken) throw new Error('Google sign-in succeeded but no access token was returned.');
    25→
    26→  GoogleTokenService.set(credential.accessToken, 3600, ALL_SCOPES);
    27→  return credential.accessToken;
    28→}
