    19→function getFYBounds(): { start: string; end: string } {
    20→  const now = new Date();
    21→  const month = now.getMonth() + 1;
    22→  const year = now.getFullYear();
    23→  const fyStart = month >= 4 ? year : year - 1;
    24→  return { start: `${fyStart}-04-01`, end: `${fyStart + 1}-03-31` };
