    27→function filterFY<T extends { date?: string; created_at?: string }>(
    28→  items: T[],
    29→  today: string,
    30→): T[] {
    31→  const { start, end } = getFYBounds();
    32→  return items.filter(it => {
    33→    const d = (it as any).date || (it as any).created_at || '';
    34→    const dateStr = d.length >= 10 ? d.slice(0, 10) : '';
    35→    return dateStr >= start && dateStr <= end && dateStr < today;
