    11→ *   B2C Large (Table 5) — Inter-state invoices > ₹2.5L to unregistered
    12→ *   B2C Small (Table 7) — All other invoices to unregistered buyers
    13→ *   HSN  (Table 12) — HSN-wise summary of outward supplies
    14→ *   Docs (Table 13) — Document summary (invoice count)
    15→ *
    16→ * HOW TO USE GENERATED FILE:
    17→ *   1. Download the JSON file
    18→ *   2. Go to gst.gov.in → Returns → GSTR-1 → Upload JSON
    19→ *   3. Review, validate, then submit
    20→ *
    21→ * NOTE: The RapidAPI GST endpoint (gst-return-status.p.rapidapi.com)
    22→ *       only supports GSTIN lookup — it cannot generate or file returns.
    23→ *       There is no public API for GSTR filing; the official route is
    24→ *       the GST Offline Tool JSON format used here.
    25→ */
    26→
    27→import { calculateGst, GST_STATE_CODES } from '../utils/gstUtils';
    28→import { exportService } from './export';
    29→
    30→// ─── Types ────────────────────────────────────────────────────────────────────
    31→
    32→export interface GSTR1ExportOptions {
    33→  /** Ledger entries from Firestore */
    34→  ledgerEntries : any[];
    35→  /** Parties (used to look up GSTIN by party_name when entry lacks one) */
    36→  parties?      : any[];
    37→  /** App settings (profile.gstin, profile.firm_name, etc.) */
    38→  settings      : any;
    39→  /** YYYY-MM e.g. "2024-11" */
    40→  month         : string;
    41→  /** "json" | "excel" | "csv" — defaults to "json" */
    42→  format?       : 'json' | 'excel' | 'csv';
    43→}
    44→
    45→interface InvoiceLine {
    46→  itemName   : string;
    47→  hsnCode    : string;
    48→  quantity   : number;
    49→  unit       : string;
    50→  rate       : number;
    51→  gstPercent : number;
    52→  taxableVal : number;
    53→  cgst       : number;
    54→  sgst       : number;
    55→  igst       : number;
    56→  total      : number;
    57→}
    58→
    59→interface ProcessedInvoice {
    60→  invNo      : string;
    61→  invDate    : string;          // DD-MM-YYYY
    62→  invType    : 'R' | 'SEWP' | 'DE'; // Regular / SEZ with payment / Deemed export
    63→  partyName  : string;
    64→  partyGstin : string;
    65→  partyState : string;
    66→  partyStateCode: string;
    67→  isInterstate: boolean;
    68→  lines      : InvoiceLine[];
    69→  taxableVal : number;
    70→  totalCgst  : number;
    71→  totalSgst  : number;
    72→  totalIgst  : number;
    73→  totalGst   : number;
    74→  grandTotal : number;
    75→}
    76→
    77→// ─── Helpers ─────────────────────────────────────────────────────────────────
    78→
    79→function toYYYYMMDD(raw: any): string {
    80→  if (!raw) return '';
    81→  if (raw?.toDate) {
    82→    const dt = raw.toDate();
    83→    return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}-${String(dt.getDate()).padStart(2, '0')}`;
    84→  }
    85→  return String(raw).substring(0, 10);
    86→}
    87→
    88→function toDDMMYYYY(raw: any): string {
    89→  const s = toYYYYMMDD(raw);
    90→  try {
    91→    const [y, m, d] = s.split('-');
    92→    return `${d}-${m}-${y}`;
    93→  } catch { return s; }
    94→}
    95→
    96→function r2(n: number) { return Math.round(n * 100) / 100; }
    97→
    98→function getStateFromGstin(gstin: string): { code: string; name: string } {
    99→  if (!gstin || gstin.length < 2) return { code: '00', name: 'Unknown' };
   100→  const code = parseInt(gstin.substring(0, 2), 10);
   101→  return { code: String(code).padStart(2, '0'), name: GST_STATE_CODES[code] || 'Unknown' };
   102→}
   103→
   104→function isInterstate(sellerGstin: string, buyerGstin: string): boolean {
   105→  if (!sellerGstin || !buyerGstin || buyerGstin.length < 2) return false;
   106→  return sellerGstin.substring(0, 2) !== buyerGstin.substring(0, 2);
   107→}
   108→
   109→function financialYear(month: string): string {
   110→  const [y, m] = month.split('-').map(Number);
   111→  const startYear = m >= 4 ? y : y - 1;
   112→  return `${startYear}-${String(startYear + 1).slice(-2)}`;
   113→}
   114→
   115→function monthLabel(month: string): string {
   116→  const [y, m] = month.split('-').map(Number);
   117→  const names = ['', 'January', 'February', 'March', 'April', 'May', 'June',
   118→                 'July', 'August', 'September', 'October', 'November', 'December'];
   119→  return `${names[m]} ${y}`;
   120→}
   121→
   122→// ─── Core Processor ──────────────────────────────────────────────────────────
   123→
   124→function processLedgerEntries(
   125→  entries  : any[],
   126→  month    : string,
   127→  sellerGstin: string,
   128→  parties  : any[] = [],
   129→): ProcessedInvoice[] {
   130→  const [y, m] = month.split('-').map(Number);
   131→
   132→  // Build a case-insensitive lookup: party_name → gstin (only parties that have a GSTIN)
   133→  const partyGstinByName = new Map<string, string>();
   134→  for (const p of parties) {
   135→    const name = (p?.name || '').trim().toLowerCase();
   136→    const g    = (p?.gstin || '').trim().toUpperCase();
   137→    if (name && g.length === 15) partyGstinByName.set(name, g);
   138→  }
   139→
   140→  return entries
   141→    .filter(e => {
   142→      // Only SELL invoices in the selected month
   143→      if (e.type !== 'sell') return false;
   144→      if (!e.date) return false;
   145→      const dateStr = toYYYYMMDD(e.date);
   146→      const [ey, em] = dateStr.split('-').map(Number);
   147→      return ey === y && em === m;
   148→    })
   149→    .map(e => {
   150→      // GSTIN may be on the ledger entry directly, or fetched from the linked party
   151→      let partyGstin = (e.gstin || '').trim().toUpperCase();
   152→      if (partyGstin.length !== 15) {
   153→        const lookupKey = (e.party_name || '').trim().toLowerCase();
   154→        const fromParty = lookupKey ? partyGstinByName.get(lookupKey) : '';
   155→        if (fromParty) partyGstin = fromParty;
   156→      }
   157→      const interstate = isInterstate(sellerGstin, partyGstin);
   158→      const partyStateInfo = getStateFromGstin(partyGstin);
   159→
   160→      // For B2C (no buyer GSTIN), use seller's state as the place of supply (intra-state default)
   161→      // or the entry's explicit place_of_supply field if present
   162→      const posGstin = partyGstin.length >= 15
   163→        ? partyGstin
   164→        : ((e.place_of_supply || '').trim() || sellerGstin);
   165→      const partyStateInfoResolved = partyGstin.length >= 15
   166→        ? partyStateInfo
   167→        : getStateFromGstin(posGstin);
   168→
   169→      const lines: InvoiceLine[] = (e.items || []).map((item: any) => {
   170→        const qty      = Number(item.quantity) || 1;
   171→        const rate     = Number(item.rate)     || 0;
   172→        const gstPct   = Number(item.gst_percent) || 0;
   173→        const lineAmt  = r2(qty * rate);
   174→        const gst      = calculateGst(lineAmt, gstPct, 'exclusive', interstate);
   175→
   176→        return {
   177→          itemName  : item.item_name || '',
   178→          hsnCode   : (item.hsn_code || '').trim(),
   179→          quantity  : qty,
   180→          unit      : item.unit || 'NOS',
   181→          rate,
   182→          gstPercent: gstPct,
   183→          taxableVal: gst.baseAmount,
   184→          cgst      : gst.cgst,
   185→          sgst      : gst.sgst,
   186→          igst      : gst.igst,
   187→          total     : gst.grandTotal,
   188→        } as InvoiceLine;
   189→      });
   190→
   191→      const taxableVal = r2(lines.reduce((s, l) => s + l.taxableVal, 0));
   192→      const totalCgst  = r2(lines.reduce((s, l) => s + l.cgst, 0));
   193→      const totalSgst  = r2(lines.reduce((s, l) => s + l.sgst, 0));
   194→      const totalIgst  = r2(lines.reduce((s, l) => s + l.igst, 0));
   195→      const totalGst   = r2(totalCgst + totalSgst + totalIgst);
   196→      const grandTotal = r2(taxableVal + totalGst);
   197→
   198→      return {
   199→        invNo    : e.invoice_no || e.prefixed_id || `INV-${e.id?.slice(-6)}`,
   200→        invDate  : toDDMMYYYY(e.date),
   201→        invType  : 'R' as const,
   202→        partyName: e.party_name || '',
   203→        partyGstin,
   204→        partyState    : partyStateInfoResolved.name,
   205→        partyStateCode: partyStateInfoResolved.code,
   206→        isInterstate  : interstate,
   207→        lines,
   208→        taxableVal,
   209→        totalCgst,
   210→        totalSgst,
   211→        totalIgst,
   212→        totalGst,
   213→        grandTotal,
   214→      } as ProcessedInvoice;
   215→    });
   216→}
   217→
   218→// ─── JSON Builder (GST Offline Tool format) ───────────────────────────────────
   219→
   220→function buildGSTR1Json(invoices: ProcessedInvoice[], sellerGstin: string, month: string): object {
   221→  const [y, m] = month.split('-').map(Number);
   222→  const retPeriod = `${String(m).padStart(2, '0')}${y}`; // MMYYYY
   223→
   224→  // ── Table 4: B2B (Registered buyer) ──
   225→  const b2bMap = new Map<string, any>();
   226→  for (const inv of invoices.filter(i => i.partyGstin.length === 15)) {
   227→    if (!b2bMap.has(inv.partyGstin)) {
   228→      b2bMap.set(inv.partyGstin, { ctin: inv.partyGstin, inv: [] });
   229→    }
   230→    const taxRates: any[] = [];
   231→    const rateMap = new Map<number, { txval: number; iamt: number; camt: number; samt: number; csamt: number }>();
   232→    for (const l of inv.lines) {
   233→      const ex = rateMap.get(l.gstPercent) || { txval: 0, iamt: 0, camt: 0, samt: 0, csamt: 0 };
   234→      rateMap.set(l.gstPercent, {
   235→        txval : r2(ex.txval + l.taxableVal),
   236→        iamt  : r2(ex.iamt  + l.igst),
   237→        camt  : r2(ex.camt  + l.cgst),
   238→        samt  : r2(ex.samt  + l.sgst),
   239→        csamt : 0,
   240→      });
   241→    }
   242→    rateMap.forEach((vals, rt) => taxRates.push({ rt, ...vals }));
   243→
   244→    b2bMap.get(inv.partyGstin)!.inv.push({
   245→      inum : inv.invNo,
   246→      idt  : inv.invDate,
   247→      val  : inv.grandTotal,
   248→      pos  : inv.partyStateCode,
   249→      rchrg: 'N',
   250→      inv_typ: inv.invType,
   251→      itms : taxRates.map(tr => ({
   252→        num  : 1,
   253→        itm_det: {
   254→          rt   : tr.rt,
   255→          txval: tr.txval,
   256→          iamt : tr.iamt,
   257→          camt : tr.camt,
   258→          samt : tr.samt,
   259→          csamt: tr.csamt,
   260→        }
   261→      })),
   262→    });
   263→  }
   264→  const b2b = Array.from(b2bMap.values());
   265→
   266→  // ── Table 5 & 7: B2C (Unregistered buyers) ──
   267→  const b2cs: any[] = [];  // inter-state > 2.5L (Table 5)
   268→  const b2csm = new Map<string, any>();
   269→  for (const inv of invoices.filter(i => i.partyGstin.length !== 15 && i.isInterstate && i.grandTotal > 250000)) {
   270→    const key = `${inv.partyStateCode}`;
   271→    const rateMap = new Map<number, { txval: number; iamt: number; csamt: number }>();
   272→    for (const l of inv.lines) {
   273→      const ex = rateMap.get(l.gstPercent) || { txval: 0, iamt: 0, csamt: 0 };
   274→      rateMap.set(l.gstPercent, { txval: r2(ex.txval + l.taxableVal), iamt: r2(ex.iamt + l.igst), csamt: 0 });
   275→    }
   276→    rateMap.forEach((vals, rt) => {
   277→      const k = `${key}_${rt}`;
   278→      if (!b2csm.has(k)) b2csm.set(k, { sply_ty: 'INTER', pos: key, rt, txval: 0, iamt: 0, csamt: 0 });
   279→      const ex = b2csm.get(k)!;
   280→      ex.txval = r2(ex.txval + vals.txval);
   281→      ex.iamt  = r2(ex.iamt  + vals.iamt);
   282→    });
   283→  }
   284→  b2csm.forEach(v => b2cs.push(v));
   285→
   286→  // B2C Small (Table 7) — all other unregistered
   287→  const b2cl: any[] = [];
   288→  const b2clm = new Map<string, any>();
   289→  for (const inv of invoices.filter(i => i.partyGstin.length !== 15 && !(i.isInterstate && i.grandTotal > 250000))) {
   290→    const sply_ty = inv.isInterstate ? 'INTER' : 'INTRA';
   291→    for (const l of inv.lines) {
   292→      const k = `${sply_ty}_${l.gstPercent}`;
   293→      if (!b2clm.has(k)) b2clm.set(k, { sply_ty, rt: l.gstPercent, txval: 0, iamt: 0, camt: 0, samt: 0, csamt: 0 });
   294→      const ex = b2clm.get(k)!;
   295→      ex.txval = r2(ex.txval + l.taxableVal);
   296→      ex.iamt  = r2(ex.iamt  + l.igst);
   297→      ex.camt  = r2(ex.camt  + l.cgst);
   298→      ex.samt  = r2(ex.samt  + l.sgst);
   299→    }
   300→  }
   301→  b2clm.forEach(v => b2cl.push(v));
   302→
   303→  // ── Table 12: HSN Summary ──
   304→  const hsnMap = new Map<string, any>();
   305→  for (const inv of invoices) {
   306→    for (const l of inv.lines) {
   307→      const hsnKey = l.hsnCode || 'MISC';
   308→      if (!hsnMap.has(hsnKey)) hsnMap.set(hsnKey, { num: hsnMap.size + 1, hsn_sc: hsnKey, desc: l.itemName, uqc: l.unit, qty: 0, val: 0, txval: 0, iamt: 0, camt: 0, samt: 0, csamt: 0, rt: l.gstPercent });
   309→      const ex = hsnMap.get(hsnKey)!;
   310→      ex.qty   = r2(ex.qty   + l.quantity);
   311→      ex.val   = r2(ex.val   + l.total);
   312→      ex.txval = r2(ex.txval + l.taxableVal);
   313→      ex.iamt  = r2(ex.iamt  + l.igst);
   314→      ex.camt  = r2(ex.camt  + l.cgst);
   315→      ex.samt  = r2(ex.samt  + l.sgst);
   316→    }
   317→  }
   318→  const hsn = { data: Array.from(hsnMap.values()) };
   319→
   320→  // ── Table 13: Document Summary ──
   321→  const docSum = {
   322→    doc_det: [{
   323→      doc_num : 1,
   324→      doc_typ : 'Invoices for outward supply',
   325→      docs    : [{ num: invoices.length, from: invoices[0]?.invNo || '', to: invoices[invoices.length - 1]?.invNo || '', totnum: invoices.length, cancel: 0, net_issue: invoices.length }],
   326→    }],
   327→  };
   328→
   329→  return {
   330→    gstin   : sellerGstin,
   331→    fp      : retPeriod,
   332→    version : 'GST3.0.4',
   333→    hash    : 'hash',
   334→    b2b,
   335→    b2cl    : b2cs,   // Table 5 — B2C Large (inter-state > ₹2.5L)
   336→    b2cs    : b2cl,   // Table 7 — B2C Small (all other unregistered)
   337→    hsn,
   338→    doc_issue: docSum,
   339→  };
   340→}
   341→
   342→// ─── CSV Builder ─────────────────────────────────────────────────────────────
   343→
   344→function buildGSTR1Csv(invoices: ProcessedInvoice[], month: string): string {
   345→  const rows: string[][] = [];
   346→
   347→  // ── B2B Section ──
   348→  rows.push(['=== TABLE 4: B2B INVOICES (Registered Buyers) ===']);
   349→  rows.push(['GSTIN of Recipient', 'Receiver Name', 'Invoice No', 'Invoice Date', 'Invoice Value',
   350→             'Place of Supply', 'Reverse Charge', 'Applicable Tax Rate', 'Invoice Type',
   351→             'Taxable Value', 'IGST', 'CGST', 'SGST', 'Cess']);
   352→  for (const inv of invoices.filter(i => i.partyGstin.length === 15)) {
   353→    for (const l of inv.lines) {
   354→      rows.push([
   355→        inv.partyGstin, inv.partyName, inv.invNo, inv.invDate,
   356→        String(inv.grandTotal), `${inv.partyStateCode}-${inv.partyState}`,
   357→        'N', String(l.gstPercent), inv.invType,
   358→        String(l.taxableVal), String(l.igst), String(l.cgst), String(l.sgst), '0',
   359→      ]);
   360→    }
   361→  }
   362→
   363→  rows.push([]);
   364→  rows.push(['=== TABLE 7: B2C INVOICES (Unregistered Buyers) ===']);
   365→  rows.push(['Type', 'Applicable Tax Rate', 'Place of Supply', 'Taxable Value', 'IGST', 'CGST', 'SGST', 'Cess']);
   366→  const b2clm = new Map<string, any>();
   367→  for (const inv of invoices.filter(i => i.partyGstin.length !== 15)) {
   368→    for (const l of inv.lines) {
   369→      const k = `${inv.isInterstate ? 'INTER' : 'INTRA'}_${l.gstPercent}_${inv.partyStateCode}`;
   370→      if (!b2clm.has(k)) b2clm.set(k, { type: inv.isInterstate ? 'Inter-State' : 'Intra-State', rt: l.gstPercent, pos: `${inv.partyStateCode}-${inv.partyState}`, txval: 0, igst: 0, cgst: 0, sgst: 0 });
   371→      const ex = b2clm.get(k)!;
   372→      ex.txval = r2(ex.txval + l.taxableVal);
   373→      ex.igst  = r2(ex.igst  + l.igst);
   374→      ex.cgst  = r2(ex.cgst  + l.cgst);
   375→      ex.sgst  = r2(ex.sgst  + l.sgst);
   376→    }
   377→  }
   378→  b2clm.forEach(v => rows.push([v.type, String(v.rt), v.pos, String(v.txval), String(v.igst), String(v.cgst), String(v.sgst), '0']));
   379→
   380→  rows.push([]);
   381→  rows.push(['=== TABLE 12: HSN-WISE SUMMARY ===']);
   382→  rows.push(['HSN', 'Description', 'UQC', 'Total Quantity', 'Total Value', 'Taxable Value', 'IGST', 'CGST', 'SGST', 'Cess']);
   383→  const hsnMap = new Map<string, any>();
   384→  for (const inv of invoices) {
   385→    for (const l of inv.lines) {
   386→      const k = l.hsnCode || 'MISC';
   387→      if (!hsnMap.has(k)) hsnMap.set(k, { hsn: k, desc: l.itemName, uqc: l.unit, qty: 0, val: 0, txval: 0, igst: 0, cgst: 0, sgst: 0 });
   388→      const ex = hsnMap.get(k)!;
   389→      ex.qty   = r2(ex.qty   + l.quantity);
   390→      ex.val   = r2(ex.val   + l.total);
   391→      ex.txval = r2(ex.txval + l.taxableVal);
   392→      ex.igst  = r2(ex.igst  + l.igst);
   393→      ex.cgst  = r2(ex.cgst  + l.cgst);
   394→      ex.sgst  = r2(ex.sgst  + l.sgst);
   395→    }
   396→  }
   397→  hsnMap.forEach(v => rows.push([v.hsn, v.desc, v.uqc, String(v.qty), String(v.val), String(v.txval), String(v.igst), String(v.cgst), String(v.sgst), '0']));
   398→
   399→  rows.push([]);
   400→  // Grand totals
   401→  const total = invoices.reduce((acc, inv) => ({
   402→    taxable: r2(acc.taxable + inv.taxableVal),
   403→    igst   : r2(acc.igst    + inv.totalIgst),
   404→    cgst   : r2(acc.cgst    + inv.totalCgst),
   405→    sgst   : r2(acc.sgst    + inv.totalSgst),
   406→    grand  : r2(acc.grand   + inv.grandTotal),
   407→  }), { taxable: 0, igst: 0, cgst: 0, sgst: 0, grand: 0 });
   408→
   409→  rows.push([`GSTR-1 Summary for ${monthLabel(month)}`]);
   410→  rows.push(['Total Invoices', String(invoices.length)]);
   411→  rows.push(['Total Taxable Value', String(total.taxable)]);
   412→  rows.push(['Total IGST', String(total.igst)]);
   413→  rows.push(['Total CGST', String(total.cgst)]);
   414→  rows.push(['Total SGST', String(total.sgst)]);
   415→  rows.push(['Total GST', String(r2(total.igst + total.cgst + total.sgst))]);
   416→  rows.push(['Grand Total', String(total.grand)]);
   417→
   418→  return rows.map(r => r.map(v => {
   419→    const s = String(v ?? '');
   420→    return (s.includes(',') || s.includes('"')) ? `"${s.replace(/"/g, '""')}"` : s;
   421→  }).join(',')).join('\n');
   422→}
