   424→// ─── Excel (XLSX) Builder ─────────────────────────────────────────────────────
   425→
   426→async function buildGSTR1Excel(invoices: ProcessedInvoice[], sellerGstin: string, month: string): Promise<Blob> {
   427→  // Build a real multi-sheet .xlsx using SheetJS. We dynamic-import the
   428→  // ~600 KB `xlsx` package so it's only fetched when the user actually
   429→  // requests an Excel export — keeps the main bundle small.
   430→  //
   431→  // BUG FIX (2026-04): previously this checked `window.XLSX`, which is
   432→  // never set in this app, so every "Excel" export silently fell through
   433→  // to the CSV branch below — but the file was still named `.xlsx`, so
   434→  // Excel would refuse to open it with a "file is corrupted" error.
   435→
   436→  let XLSX: any = null;
   437→  try {
   438→    XLSX = await import('xlsx');
   439→  } catch (err) {
   440→    console.error('[gstr1Export] Failed to load xlsx library:', err);
   441→  }
   442→
   443→  if (XLSX) {
   444→    const wb = XLSX.utils.book_new();
   445→
   446→    // ── B2B Sheet ──
