const handleExportParties = useCallback(async () => {
  if (filteredParties.length === 0) return showToast('No parties to export', 'error');
  const esc = (v: any) => {
    const s = String(v ?? '');
    return (s.includes(',') || s.includes('"') || s.includes('\n')) ? `"${s.replace(/"/g, '""')}"` : s;
  };
  const headers = ['Party Code', 'Name', 'Role', 'Contact', 'GSTIN', 'Legal Name', 'Address', 'State', 'Site', 'Credit Limit', 'Linked Items', 'Total Billed', 'Total Paid', 'Balance'];
  const rows = filteredParties.map(p => {
    const acc = partyAccounting[p.id] || { totalBilled: 0, totalPaid: 0, balance: 0 };
    return [
      p.party_code ?? '',
      p.name ?? '',
      p.role ?? '',
      p.contact ?? '',
      p.gstin ?? '',
      p.legal_name ?? '',
      p.address ?? '',
      p.state ?? '',
      p.site ?? '',
      p.credit_limit ?? '',
      Array.isArray(p.linked_items) ? p.linked_items.join('|') : (p.linked_items ?? ''),
      acc.totalBilled.toFixed(2),
      acc.totalPaid.toFixed(2),
      acc.balance.toFixed(2),
    ].map(esc).join(',');
  });
  const csv = [headers.map(esc).join(','), ...rows].join('\n');
  const tag = filterRole !== 'all' ? `${filterRole}_` : '';
  await exportService.shareOrDownload(csv, `Parties_${tag}${Date.now()}.csv`, 'text/csv');
  showToast('Parties exported', 'success');
}, [filteredParties, partyAccounting, filterRole, showToast]);

